  );
}

// ---------------------------------------------------------------------------
// The four configurable model roles (3 stages + general-purpose).
// ---------------------------------------------------------------------------

interface RoleDef {
  settingKey: string;
  /** null for auxiliary models — they have no pipeline-stage requirement icons. */
