export async function resolveRouteFromSettings(
  db: OracleDb,
  role: OracleModelRole,
): Promise<OracleModelRoute | null> {
  return resolvePrimaryRouteFromSettings(db, role);
}

export async function resolveAuxiliaryRouteFromSettings(
  db: OracleDb,
